import './TransactionRow.css';
import axios from 'axios';

function TransactionRow({transaction, transactions, setTransactions, isdelete}) {
    function deleteTransaction() {
        axios.delete(`http://localhost:5000/api/transactions/${transaction._id}`)
        setTransactions(transactions.filter(t => t._id !== transaction._id)
        );
    }
    return (
        <div className="row">
            <p className='transaction-type'>{transaction.type}</p>
            <p className='transaction-category'>{transaction.category}</p>
            <p className='transaction-amount'>₹{transaction.amount}</p>
            <p className='transaction-date'>{transaction.date.split("T")[0]}</p>
            {isdelete && <button className='delete-transaction-column' onClick={deleteTransaction}>X</button>}
        </div>
    )
};

export default TransactionRow;
